def object_converter(o):
    if o['__class'] == 'datetime':
        return datetime.strptime(str(o['value']), '%Y-%m-%d %H:%M:%S')
        
    elif o.__class__.__name__ in ['str','int',  'long',   'float']:  
        return str(o)
def default_converter(o):
    if isinstance(o, (datetime)):
        return {"__class__": "datetime", "value":o}

